# Example: Expense filing with opposing agents
# "I have two subagents, one that represents me and one 
#  that represents the company. They do battle to figure 
#  out what's the proper actual set of expenses."

class DebateOrchestrator:
    def debate(self, task):
        advocate = Agent(role='pro_user')
        auditor = Agent(role='pro_company')

        proposal = advocate.propose(task)
        critique = auditor.challenge(proposal)

        for _ in range(max_rounds):
            response = advocate.defend(critique)
            critique = auditor.challenge(response)
            if consensus_reached(response, critique):
                break

        return synthesize(proposal, critiques)
